import React, { useEffect, useState } from "react";
import { Box, Button, Typography, Paper } from "@mui/material";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import axios from "axios";
import { useAuth } from "../../contexts/AuthContext";
import { io } from "socket.io-client";

const socket = io("http://localhost:5000");

export default function RiderDashboard() {
  const { auth } = useAuth();
  const [pendingRides, setPendingRides] = useState([]);
  const [currentRide, setCurrentRide] = useState(null);
  const [coords, setCoords] = useState(null);

  // 📍 Rider GPS tracking
  useEffect(() => {
    const interval = setInterval(() => {
      if (coords && currentRide) {
        socket.emit("driverLocationUpdate", { rideId: currentRide._id, coords });
        // ✅ check if driver close to pickup
        const distance = getDistance(coords, currentRide.pickupCoords);
        if (distance < 0.1) {
          socket.emit("driverArrived", { rideId: currentRide._id });
        }
      }
    }, 5000);
    return () => clearInterval(interval);
  }, [coords, currentRide]);

  // 📍 Get current location
  useEffect(() => {
    navigator.geolocation.watchPosition(
      (pos) => {
        setCoords({ lat: pos.coords.latitude, lng: pos.coords.longitude });
      },
      (err) => console.error("GPS error:", err),
      { enableHighAccuracy: true }
    );
  }, []);

  // 🚖 Fetch rides
  const fetchPendingRides = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/rides/pending", {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      setPendingRides(res.data.rides || []);
    } catch (err) {
      console.error("❌ Failed to fetch rides");
    }
  };

  useEffect(() => {
    fetchPendingRides();
  }, []);

  // 🚖 Accept Ride
  const acceptRide = async (id) => {
    try {
      const res = await axios.post(
        `http://localhost:5000/api/rides/${id}/accept`,
        {},
        { headers: { Authorization: `Bearer ${auth?.token}` } }
      );
      setCurrentRide(res.data.ride);
      setPendingRides([]);
    } catch (err) {
      console.error("❌ Failed to accept ride");
    }
  };

  const rejectRide = async (id) => {
    try {
      await axios.post(
        `http://localhost:5000/api/rides/${id}/reject`,
        {},
        { headers: { Authorization: `Bearer ${auth?.token}` } }
      );
      fetchPendingRides();
    } catch (err) {
      console.error("❌ Failed to reject ride");
    }
  };

  // Helper: distance in km
  const getDistance = (a, b) => {
    if (!a || !b) return Infinity;
    const R = 6371;
    const dLat = ((b.lat - a.lat) * Math.PI) / 180;
    const dLng = ((b.lng - a.lng) * Math.PI) / 180;
    const lat1 = (a.lat * Math.PI) / 180;
    const lat2 = (b.lat * Math.PI) / 180;
    const hav =
      Math.sin(dLat / 2) ** 2 +
      Math.sin(dLng / 2) ** 2 * Math.cos(lat1) * Math.cos(lat2);
    return 2 * R * Math.asin(Math.sqrt(hav));
  };

  const driverIcon = new L.Icon({
    iconUrl: "https://cdn-icons-png.flaticon.com/512/64/64113.png",
    iconSize: [30, 30],
  });

  return (
    <Box p={3}>
      <Typography variant="h5">Pending Ride Requests</Typography>
      {pendingRides.length === 0 ? (
        <Typography>No rides</Typography>
      ) : (
        pendingRides.map((ride) => (
          <Paper key={ride._id} sx={{ p: 2, my: 2 }}>
            <Typography>Pickup: {ride.pickup}</Typography>
            <Typography>Drop: {ride.drop}</Typography>
            <Button color="success" variant="contained" onClick={() => acceptRide(ride._id)}>
              Accept
            </Button>
            <Button color="error" variant="contained" onClick={() => rejectRide(ride._id)} sx={{ ml: 2 }}>
              Reject
            </Button>
          </Paper>
        ))
      )}

      <Typography variant="h5" sx={{ mt: 4 }}>Live Map</Typography>
      {coords && (
        <MapContainer center={coords} zoom={14} style={{ height: "500px", width: "100%" }}>
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
          <Marker position={coords} icon={driverIcon}>
            <Popup>You (Driver)</Popup>
          </Marker>
        </MapContainer>
      )}
    </Box>
  );
}
